head.b:skin:
/*
  Theme name: Hearth Review
  Direction: a calm Korean affiliate and AdSense blog theme.
  The design intentionally avoids: dark UI, news portal layout, progress bars, reading-time badges,
  noisy gradients, generic AI landing-page sections, and platform-specific share button clutter.
*/

/* 01. Foundation --------------------------------------------------------- */
:root {
  --page: #fbfaf6;
  --paper: #fffefb;
  --paper-warm: #fff8ed;
  --paper-green: #f3faf6;
  --ink: #27231f;
  --ink-2: #4a423a;
  --muted: #756c62;
  --faint: #9a9085;
  --line: #e8dfd2;
  --line-2: #d8c8b2;
  --brand: #8a4f20;
  --brand-2: #b66d2d;
  --green: #276457;
  --green-soft: #eaf5f1;
  --yellow: #fff0c6;
  --red-soft: #fff2ef;
  --shadow: 0 18px 46px rgba(64, 45, 26, .10);
  --shadow-soft: 0 8px 22px rgba(64, 45, 26, .07);
  --radius-xl: 30px;
  --radius-lg: 22px;
  --radius-md: 16px;
  --radius-sm: 10px;
  --container: 1160px;
  --article: 760px;
  --sidebar: 320px;
  --gap: 32px;
  --font: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Noto Sans KR", "Apple SD Gothic Neo", Arial, sans-serif;
  --serif: Georgia, "Noto Serif KR", serif;
}
* { box-sizing: border-box; }
html { scroll-behavior: smooth; }
body {
  margin: 0;
  background:
    radial-gradient(circle at 10% 0%, rgba(255, 240, 198, .48), transparent 34rem),
    linear-gradient(180deg, #fffdf8 0, var(--page) 420px, var(--page) 100%);
  color: var(--ink);
  font-family: var(--font);
  font-size: 17px;
  line-height: 1.76;
  letter-spacing: -.01em;
  -webkit-font-smoothing: antialiased;
  text-rendering: optimizeLegibility;
}
a { color: var(--brand); text-decoration-thickness: .08em; text-underline-offset: .18em; }
a:hover { color: #653713; }
img, iframe, video { max-width: 100%; }
img { height: auto; border-radius: var(--radius-md); }
button, input, textarea, select { font: inherit; }
button { cursor: pointer; }
::selection { background: var(--yellow); color: #19130d; }
.skip-link {
  position: absolute;
  top: -72px;
  left: 16px;
  z-index: 9999;
  padding: 10px 14px;
  border-radius: var(--radius-sm);
  background: #fff;
  color: #111;
  box-shadow: var(--shadow-soft);
}
.skip-link:focus { top: 14px; }
.wrap { max-width: var(--container); margin: 0 auto; padding: 0 20px; }

/* 02. Header ------------------------------------------------------------- */
.notice-bar {
  border-bottom: 1px solid var(--line);
  background: rgba(255, 248, 237, .88);
  color: #5f5143;
  font-size: 14px;
}
.notice-bar .wrap { display: flex; justify-content: center; padding-top: 7px; padding-bottom: 7px; }
.site-header {
  position: sticky;
  top: 0;
  z-index: 50;
  border-bottom: 1px solid rgba(232, 223, 210, .86);
  background: rgba(255, 254, 251, .94);
  backdrop-filter: blur(14px) saturate(150%);
}
.header-grid { display: flex; align-items: center; gap: 18px; min-height: 76px; }
.brand { display: flex; align-items: center; min-width: 0; gap: 12px; }
.brand-symbol {
  width: 42px;
  height: 42px;
  flex: 0 0 auto;
  border-radius: 14px;
  display: grid;
  place-items: center;
  background: #fff4df;
  color: var(--brand);
  border: 1px solid #ead5b5;
  font-weight: 900;
}
.Header h1, .Header .title { margin: 0; font-size: 23px; line-height: 1.22; letter-spacing: -.045em; }
.Header h1 a, .Header .title a { color: var(--ink); text-decoration: none; }
.Header .description { margin: 3px 0 0; color: var(--muted); font-size: 13px; line-height: 1.35; }
.menu-button {
  display: none;
  margin-left: auto;
  border: 1px solid var(--line);
  background: #fff;
  color: var(--ink);
  border-radius: 999px;
  padding: 9px 13px;
  font-weight: 800;
}
.nav-panel { margin-left: auto; display: flex; align-items: center; gap: 14px; }
.nav-panel .PageList ul, .nav-panel .LinkList ul { list-style: none; display: flex; align-items: center; gap: 3px; margin: 0; padding: 0; }
.nav-panel .PageList a, .nav-panel .LinkList a {
  display: block;
  padding: 9px 12px;
  color: #38312b;
  border-radius: 999px;
  text-decoration: none;
  font-weight: 760;
  font-size: 14px;
}
.nav-panel .PageList a:hover, .nav-panel .LinkList a:hover { background: var(--paper-warm); color: var(--brand); }
.search-form { position: relative; }
.search-form input {
  width: 190px;
  border: 1px solid var(--line);
  background: #fff;
  border-radius: 999px;
  padding: 10px 40px 10px 14px;
  outline: 0;
}
.search-form input:focus { border-color: #c99d65; box-shadow: 0 0 0 4px rgba(182, 109, 45, .12); }
.search-form button {
  position: absolute;
  right: 4px;
  top: 4px;
  width: 32px;
  height: 32px;
  border: 0;
  border-radius: 50%;
  background: var(--brand);
  color: #fff;
}

/* 03. Layout ------------------------------------------------------------- */
.layout { display: grid; grid-template-columns: minmax(0, 1fr) var(--sidebar); gap: var(--gap); align-items: start; padding-top: 34px; padding-bottom: 56px; }
.content { min-width: 0; }
.sidebar { min-width: 0; position: sticky; top: 98px; }
.hero {
  margin-bottom: 22px;
  padding: 34px;
  border-radius: var(--radius-xl);
  border: 1px solid var(--line);
  background: linear-gradient(135deg, #fffefb, #fff5e4);
  box-shadow: var(--shadow);
}
.hero h2 { margin: 0 0 10px; font-size: clamp(29px, 4vw, 45px); line-height: 1.14; letter-spacing: -.06em; }
.hero p { max-width: 740px; margin: 0; color: var(--ink-2); }
.promise-row { display: grid; grid-template-columns: repeat(3, 1fr); gap: 12px; margin: 0 0 26px; }
.promise { padding: 14px 16px; border: 1px solid var(--line); border-radius: var(--radius-md); background: rgba(255,255,255,.74); color: #594d42; font-weight: 800; font-size: 14px; }

/* 04. Widgets ------------------------------------------------------------ */
.widget {
  margin: 0 0 20px;
  padding: 20px;
  border: 1px solid var(--line);
  border-radius: var(--radius-lg);
  background: var(--paper);
  box-shadow: var(--shadow-soft);
}
.widget-title, .sidebar .title, .footer .title { margin: 0 0 13px; font-size: 16px; letter-spacing: -.025em; }
.PopularPosts ul, .Label ul, .BlogArchive ul, .LinkList ul { list-style: none; margin: 0; padding: 0; }
.sidebar .PopularPosts li, .sidebar .Label li, .sidebar .BlogArchive li, .sidebar .LinkList li { padding: 10px 0; border-top: 1px solid var(--line); }
.sidebar .PopularPosts li:first-child, .sidebar .Label li:first-child, .sidebar .BlogArchive li:first-child, .sidebar .LinkList li:first-child { border-top: 0; }
.Label a, .label-chip {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  margin: 4px 5px 4px 0;
  padding: 5px 10px;
  border-radius: 999px;
  background: var(--paper-warm);
  border: 1px solid #ead6ba;
  color: #71471d;
  font-size: 12px;
  font-weight: 850;
  text-decoration: none;
}
.ad-box {
  display: grid;
  place-items: center;
  min-height: 104px;
  padding: 16px;
  border: 1px dashed #d3b58a;
  border-radius: var(--radius-md);
  background: repeating-linear-gradient(135deg, #fffaf2, #fffaf2 10px, #fff4e4 10px, #fff4e4 20px);
  color: #8b6c49;
  text-align: center;
  font-size: 13px;
}
.ad-box.small { min-height: 74px; }

/* 05. Post list ---------------------------------------------------------- */
.post-card {
  display: grid;
  grid-template-columns: 238px minmax(0, 1fr);
  gap: 22px;
  margin-bottom: 22px;
  padding: 18px;
  border: 1px solid var(--line);
  border-radius: 26px;
  background: var(--paper);
  box-shadow: var(--shadow);
}
.post-card:hover { border-color: #d8bd91; transform: translateY(-1px); transition: transform .18s ease, border-color .18s ease; }
.thumb {
  position: relative;
  display: block;
  overflow: hidden;
  aspect-ratio: 16 / 10;
  border-radius: 20px;
  background: #f3dfbf;
  color: inherit;
  text-decoration: none;
}
.thumb img { width: 100%; height: 100%; object-fit: cover; border-radius: 0; }
.auto-thumb {
  width: 100%;
  height: 100%;
  display: grid;
  place-items: center;
  padding: 20px;
  text-align: center;
  color: #59350f;
  font-weight: 950;
  line-height: 1.25;
  letter-spacing: -.045em;
  background:
    radial-gradient(circle at 20% 20%, rgba(255,255,255,.85), transparent 33%),
    linear-gradient(135deg, #f7dfb8, #fff8e9 56%, #e0efe9);
}
.auto-thumb span { display: -webkit-box; -webkit-line-clamp: 4; -webkit-box-orient: vertical; overflow: hidden; }
.post-card h2 { margin: 0 0 8px; font-size: 24px; line-height: 1.3; letter-spacing: -.045em; }
.post-card h2 a { color: var(--ink); text-decoration: none; }
.post-card h2 a:hover { color: var(--brand); }
.meta { display: flex; flex-wrap: wrap; gap: 8px 11px; align-items: center; margin: 0 0 10px; color: var(--muted); font-size: 13px; }
.snippet { color: #554d45; font-size: 15px; }
.pager { display: flex; justify-content: space-between; gap: 10px; margin: 24px 0; }
.pager a { padding: 10px 14px; border: 1px solid var(--line); border-radius: 999px; background: #fff; color: var(--brand); text-decoration: none; font-weight: 850; }
.status-msg-wrap { margin-bottom: 20px; padding: 14px 18px; border: 1px solid var(--line); border-radius: var(--radius-md); background: var(--paper-warm); }

/* 06. Single article ----------------------------------------------------- */
.article {
  padding: clamp(22px, 4vw, 46px);
  border: 1px solid var(--line);
  border-radius: var(--radius-xl);
  background: var(--paper);
  box-shadow: var(--shadow);
}
.article-head { margin-bottom: 22px; }
.article-title { margin: 0 0 14px; font-size: clamp(32px, 5vw, 52px); line-height: 1.12; letter-spacing: -.065em; }
.hero-image { width: 100%; margin: 0 0 22px; border-radius: 24px; box-shadow: var(--shadow-soft); }
.article-body { font-size: 18px; line-height: 1.88; word-break: keep-all; }
.article-body > :first-child { margin-top: 0; }
.article-body p { margin: 0 0 18px; }
.article-body h2, .article-body h3, .article-body h4 { color: #211d19; line-height: 1.28; letter-spacing: -.05em; scroll-margin-top: 96px; }
.article-body h2 { margin: 44px 0 16px; padding-bottom: 10px; border-bottom: 3px solid #ead8bd; font-size: 30px; }
.article-body h2:before { content: ""; display: inline-block; width: 9px; height: 9px; margin-right: 10px; border-radius: 50%; background: var(--brand); vertical-align: middle; }
.article-body h3 { margin: 34px 0 12px; padding-left: 14px; border-left: 5px solid var(--green); font-size: 24px; }
.article-body h4 { margin: 26px 0 10px; font-size: 20px; color: #483b30; }
.article-body ul, .article-body ol { margin: 0 0 22px; padding-left: 1.35em; }
.article-body li { margin: 8px 0; }
.article-body blockquote { margin: 28px 0; padding: 19px 22px; border-left: 5px solid var(--brand); border-radius: 0 var(--radius-md) var(--radius-md) 0; background: var(--paper-warm); color: #493f36; }
.article-body mark { padding: .1em .25em; border-radius: .35em; background: var(--yellow); }
.article-body code { padding: 2px 5px; border: 1px solid #eadac4; border-radius: 6px; background: #f7eddd; font-size: .92em; }
.article-body pre { overflow: auto; padding: 18px; border-radius: var(--radius-md); background: #2b241e; color: #fff7ed; font-size: 14px; }
.article-body pre code { padding: 0; border: 0; background: transparent; color: inherit; }

/* 07. Content modules ---------------------------------------------------- */
.article-body table { width: 100%; margin: 24px 0; border: 1px solid var(--line); border-collapse: separate; border-spacing: 0; border-radius: var(--radius-md); overflow: hidden; background: #fff; font-size: 15px; }
.article-body th, .article-body td { padding: 13px 14px; border-bottom: 1px solid var(--line); vertical-align: top; }
.article-body th { background: #fbedd6; color: #38271a; text-align: left; font-weight: 900; }
.article-body tr:nth-child(even) td { background: #fffaf2; }
.article-body tr:last-child td { border-bottom: 0; }
.article-body .note, .article-body .tip, .article-body .warning, .article-body .summary, .article-body .affiliate-disclosure { margin: 24px 0; padding: 18px 20px; border-radius: var(--radius-lg); border: 1px solid var(--line); }
.article-body .note { background: var(--paper-warm); }
.article-body .tip { background: var(--green-soft); border-color: #cfe5de; }
.article-body .warning { background: var(--red-soft); border-color: #eed3ce; }
.article-body .summary { background: #fff; box-shadow: var(--shadow-soft); }
.article-body .affiliate-disclosure { background: #fffaf2; color: #5f5143; font-size: 15px; }
.article-body .pros-cons { display: grid; grid-template-columns: repeat(2, minmax(0, 1fr)); gap: 14px; margin: 24px 0; }
.article-body .pros-cons > * { padding: 18px; border: 1px solid var(--line); border-radius: var(--radius-lg); background: #fff; }
.article-body .faq-box { margin: 28px 0; border-top: 2px solid var(--line-2); }
.article-body .faq-box > * { padding: 15px 0; border-bottom: 1px solid var(--line); }
.article-body .rank-card { display: grid; grid-template-columns: 54px minmax(0, 1fr); gap: 14px; margin: 18px 0; padding: 18px; border: 1px solid var(--line); border-radius: var(--radius-lg); background: #fff; }
.article-body .rank-card:before { content: attr(data-rank); display: grid; place-items: center; width: 42px; height: 42px; border-radius: 50%; background: var(--paper-warm); color: var(--brand); font-weight: 950; }
.article-body a:not(.plain-link) { font-weight: 850; }
.article-body a[style*="font-size: medium"],
.article-body a[style*="font-size:medium"],
.article-body span[style*="font-size: medium"] a,
.article-body span[style*="font-size:medium"] a,
.article-body .buy-button {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  min-height: 46px;
  margin: 8px 0;
  padding: 12px 20px;
  border-radius: 999px;
  background: linear-gradient(135deg, var(--brand), var(--brand-2));
  color: #fff !important;
  text-decoration: none !important;
  font-weight: 950;
  box-shadow: 0 12px 24px rgba(138, 79, 32, .22);
}
.article-body a[style*="font-size: medium"]:after,
.article-body a[style*="font-size:medium"]:after,
.article-body span[style*="font-size: medium"] a:after,
.article-body span[style*="font-size:medium"] a:after,
.article-body .buy-button:after { content: "›"; font-size: 22px; line-height: 1; }

/* 08. Toc share related -------------------------------------------------- */
.toc { display: none; margin: 22px 0 30px; padding: 18px; border: 1px solid #ead6ba; border-radius: var(--radius-lg); background: var(--paper-warm); }
.toc.ready { display: block; }
.toc-head { display: flex; align-items: center; justify-content: space-between; margin-bottom: 10px; font-weight: 950; }
.toc ol { margin: 0; padding-left: 20px; }
.toc li { margin: 6px 0; }
.toc a { color: #4b3825; text-decoration: none; }
.toc a:hover { color: var(--brand); text-decoration: underline; }
.share { display: flex; flex-wrap: wrap; gap: 10px; margin: 28px 0; }
.share button { padding: 12px 18px; border-radius: 999px; font-weight: 900; }
.share-native { border: 0; background: var(--green); color: #fff; }
.share-copy { border: 1px solid var(--line); background: #fff; color: var(--ink); }
.related { margin-top: 32px; }
.related h2 { margin: 0 0 14px; font-size: 23px; line-height: 1.25; letter-spacing: -.04em; }
.related-grid { display: grid; grid-template-columns: repeat(3, minmax(0, 1fr)); gap: 14px; }
.related-card { display: block; min-height: 86px; padding: 14px; border: 1px solid var(--line); border-radius: var(--radius-md); background: #fff; color: var(--ink); text-decoration: none; }
.related-card:hover { border-color: #d3ad78; transform: translateY(-1px); }
.related-card strong { display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden; line-height: 1.35; }
.comment-area { margin-top: 24px; }

/* 09. Footer ------------------------------------------------------------- */
.footer { border-top: 1px solid var(--line); background: #fffaf2; padding: 34px 0; color: #5d554d; }
.footer-grid { display: grid; grid-template-columns: 2fr 1fr 1fr; gap: 24px; }
.footer a { color: #544334; }
.footer-note { margin-top: 18px; color: var(--muted); font-size: 13px; }

/* 10. Practical helper classes ------------------------------------------ */
.box { padding: 18px; border: 1px solid var(--line); border-radius: var(--radius-lg); background: #fff; }
.box.warm { background: var(--paper-warm); }
.box.green { background: var(--green-soft); border-color: #cfe5de; }
.grid-2 { display: grid; grid-template-columns: repeat(2, minmax(0, 1fr)); gap: 14px; }
.grid-3 { display: grid; grid-template-columns: repeat(3, minmax(0, 1fr)); gap: 14px; }
.muted { color: var(--muted); }
.center { text-align: center; }
.tight { line-height: 1.45; }
.lead { font-size: 20px; line-height: 1.7; color: var(--ink-2); }
.small { font-size: 14px; }

/* 11. Responsive --------------------------------------------------------- */
@media (max-width: 1040px) {
  :root { --sidebar: 300px; --gap: 24px; }
  .post-card { grid-template-columns: 210px minmax(0, 1fr); }
}
@media (max-width: 940px) {
  .layout { grid-template-columns: 1fr; }
  .sidebar { position: static; }
  .footer-grid { grid-template-columns: 1fr 1fr; }
  .promise-row { grid-template-columns: 1fr; }
}
@media (max-width: 760px) {
  body { font-size: 16px; }
  .wrap { padding: 0 14px; }
  .header-grid { min-height: 66px; }
  .menu-button { display: block; }
  .nav-panel { display: none; position: absolute; top: 70px; left: 14px; right: 14px; padding: 14px; border: 1px solid var(--line); border-radius: var(--radius-lg); background: #fff; box-shadow: var(--shadow); }
  .nav-panel.open { display: block; }
  .nav-panel .PageList ul, .nav-panel .LinkList ul { display: block; }
  .search-form { margin-top: 10px; }
  .search-form input { width: 100%; }
  .hero { padding: 24px; }
  .post-card { grid-template-columns: 1fr; padding: 14px; border-radius: var(--radius-lg); }
  .article { padding: 20px; border-radius: var(--radius-lg); }
  .article-body { font-size: 17px; }
  .article-body h2 { font-size: 25px; }
  .article-body h3 { font-size: 21px; }
  .article-body table { display: block; overflow-x: auto; white-space: nowrap; }
  .article-body .pros-cons, .grid-2, .grid-3, .related-grid, .footer-grid { grid-template-columns: 1fr; }
  .share button { width: 100%; }
}
@media print {
  .notice-bar, .site-header, .sidebar, .ad-box, .share, .related, .footer, .toc { display: none !important; }
  .layout { display: block; }
  .article { border: 0; box-shadow: none; padding: 0; }
}

body.script:
(function () {
  'use strict';

  var nav = document.getElementById('navPanel');
  var menu = document.querySelector('.menu-button');
  if (nav && menu) {
    menu.addEventListener('click', function () {
      var open = nav.classList.toggle('open');
      menu.setAttribute('aria-expanded', open ? 'true' : 'false');
    });
  }

  var body = document.getElementById('articleBody');
  var toc = document.getElementById('tocBox');
  var list = document.getElementById('tocList');
  if (body && toc && list) {
    var heads = [].slice.call(body.querySelectorAll('h2,h3'));
    if (heads.length > 1) {
      heads.forEach(function (head, index) {
        if (!head.id) {
          head.id = 'section-' + (index + 1);
        }
        var item = document.createElement('li');
        if (head.tagName === 'H3') {
          item.style.marginLeft = '14px';
        }
        var link = document.createElement('a');
        link.href = '#' + head.id;
        link.textContent = head.textContent.trim();
        item.appendChild(link);
        list.appendChild(item);
      });
      toc.classList.add('ready');
    }
  }

  var share = document.querySelector('.share-native');
  var copy = document.querySelector('.share-copy');
  function copyUrl() {
    if (!navigator.clipboard) {
      return;
    }
    navigator.clipboard.writeText(location.href).then(function () {
      if (copy) {
        copy.textContent = '복사 완료';
        window.setTimeout(function () { copy.textContent = '링크 복사'; }, 1700);
      }
    });
  }
  if (share) {
    share.addEventListener('click', function () {
      if (navigator.share) {
        navigator.share({ title: document.title, url: location.href }).catch(function () {});
      } else {
        copyUrl();
      }
    });
  }
  if (copy) {
    copy.addEventListener('click', copyUrl);
  }

  var related = document.getElementById('relatedGrid');
  if (related) {
    var labels = [].slice.call(document.querySelectorAll('.article .label-chip'))
      .map(function (label) { return label.textContent.trim(); })
      .filter(Boolean);
    var feed = '/feeds/posts/summary?alt=json&max-results=6';
    if (labels[0]) {
      feed = '/feeds/posts/summary/-/' + encodeURIComponent(labels[0]) + '?alt=json&max-results=6';
    }
    fetch(feed)
      .then(function (res) { return res.json(); })
      .then(function (json) {
        var entries = (json.feed && json.feed.entry) || [];
        var current = location.href.replace(/[#?].*/, '');
        entries
          .filter(function (entry) {
            var link = (entry.link || []).filter(function (item) { return item.rel === 'alternate'; })[0];
            return link && link.href.replace(/[#?].*/, '') !== current;
          })
          .slice(0, 3)
          .forEach(function (entry) {
            var link = (entry.link || []).filter(function (item) { return item.rel === 'alternate'; })[0];
            var title = entry.title && entry.title.$t ? entry.title.$t : '관련 글';
            var anchor = document.createElement('a');
            anchor.className = 'related-card';
            anchor.href = link.href;
            anchor.innerHTML = '<strong></strong>';
            anchor.querySelector('strong').textContent = title;
            related.appendChild(anchor);
          });
        if (!related.children.length && related.parentNode) {
          related.parentNode.style.display = 'none';
        }
      })
      .catch(function () {
        if (related.parentNode) {
          related.parentNode.style.display = 'none';
        }
      });
  }
}());
